import{_ as r,c as t,o as s,ah as n}from"./chunks/framework.RCw5T9E9.js";const d=JSON.parse('{"title":"История релизов","description":"","frontmatter":{"title":"История релизов"},"headers":[],"relativePath":"ru/releases/history.md","filePath":"ru/releases/history.md"}'),l={name:"ru/releases/history.md"};function i(a,o,e,g,h,u){return s(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="история-релизов" tabindex="-1">История релизов <a class="header-anchor" href="#история-релизов" aria-label="Permalink to &quot;История релизов&quot;">​</a></h1><h2 id="_2-0-0-2026-01-23" tabindex="-1">[2.0.0] - 2026-01-23 <a class="header-anchor" href="#_2-0-0-2026-01-23" aria-label="Permalink to &quot;[2.0.0] - 2026-01-23&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Добавлена поддержка корпоративной версии приложения, не требующей установки.</li><li>Добавлена система отслеживания версий и уведомлений о доступности новых обновлений.</li><li>Проект переведён в формат <strong>iframe</strong> и больше не использует <strong>popup</strong> как точку входа.</li></ul><hr><h3 id="производительность" tabindex="-1">Производительность <a class="header-anchor" href="#производительность" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Решена проблема мгновенной утечки памяти на статичных сайтах, включая <strong>Docusaurus</strong> и <strong>Hugo</strong>.</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Проведён рефакторинг стилей и общего визуального оформления продукта.</li></ul><h2 id="_2-1-0-2026-02-02" tabindex="-1">[2.1.0] - 2026-02-02 <a class="header-anchor" href="#_2-1-0-2026-02-02" aria-label="Permalink to &quot;[2.1.0] - 2026-02-02&quot;">​</a></h2><h3 id="core-1" tabindex="-1">Core <a class="header-anchor" href="#core-1" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Добавлена новая вкладка управления — <strong>Network</strong>.</li><li>Проведён редизайн приложения с учётом нового расположения в <strong>iframe</strong> вместо <strong>popup</strong>: на экране теперь доступно больше полезной информации.</li><li>Скорректирована вёрстка блоков <strong>JSON</strong> — блок отображается на всю высоту приложения.</li><li>Исправлено залипание вкладок при раннем открытии приложения: ранее для отображения вкладок <strong>Props</strong> и <strong>Pinia</strong> требовалась полная перезагрузка страницы.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена ошибка, при которой избранные элементы <strong>Props</strong> не находились после обновления страницы или повторного прохождения сценариев.</li><li>Оптимизирована работа с <strong>Props</strong> для длительных сессий без избыточной нагрузки на CPU, проведён рефакторинг внутренней логики.</li><li>Переработана вкладка <strong>Props</strong>: улучшена работа с большим количеством объектов и поиск при наведении.</li><li>Из вкладки <strong>Props</strong> удалён режим <strong>Props only</strong>.</li></ul><hr><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Добавлен перехват всех вызовов <strong>fetch</strong> и <strong>XMLHttpRequest</strong>, за исключением запросов типа <strong>OPTIONS</strong> и запросов, инициированных расширением.</li><li>Добавлено отображение сводной информации по запросам: статус, метод, имя, время выполнения, размер.</li><li>Добавлен подробный просмотр запроса с разделами: параметры, авторизация, заголовки, запрос, ответ. Отображаются только заголовки, доступные в рамках <strong>CORS</strong>-ограничений браузера.</li><li>Добавлена возможность приостановки и возобновления записи запросов. Запись включена по умолчанию при первом открытии приложения.</li><li>Добавлен <strong>Breakpoint</strong> — остановка и модификация исходящего запроса перед отправкой.</li><li>Добавлен <strong>Mock Response</strong> — перехват заранее выбранного запроса с подменой ответа.</li><li>Добавлено быстрое копирование в буфер обмена URL-адресов, токенов и ключевых элементов.</li><li>Добавлена очистка всех записанных запросов одной кнопкой.</li><li>Реализована событийная архитектура без <strong>polling</strong> для минимального использования CPU.</li><li>Добавлено автоматическое определение двоичного содержимого — для таких данных отображаются только метаданные.</li></ul><h2 id="_2-2-0-2026-02-24" tabindex="-1">[2.2.0] - 2026-02-24 <a class="header-anchor" href="#_2-2-0-2026-02-24" aria-label="Permalink to &quot;[2.2.0] - 2026-02-24&quot;">​</a></h2><h3 id="core-2" tabindex="-1">Core <a class="header-anchor" href="#core-2" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><p>Добавлена настройка <strong>Display Mode</strong> с возможностью переноса приложения во вкладку <strong>DevTools</strong> и отключения <strong>overlay</strong>-режима.</p></li><li><p>Проведён рефакторинг вкладки <strong>Options</strong> — настройки разбиты на логические разделы.</p></li><li><p>Изменена логика работы активных фильтров на вкладках <strong>Props</strong>, <strong>Pinia Store</strong> и <strong>Network</strong>: редактирование набора фильтров теперь доступно без перехода в настройки.</p></li><li><p>Исправлена область нажатия (<strong>click area</strong>) в текстовом режиме отображения <strong>JSON</strong>.</p></li><li><p>Большие <strong>JSON</strong> больше не обрезаются: для сохранения производительности при отображении отключаются CSS-стили.</p></li><li><p>Обновлена логика уведомления о новых версиях:</p><ul><li><strong>Dismiss</strong> переименована в <strong>Later</strong>;</li><li><strong>Download</strong> переименована в <strong>Preview</strong> и ведёт в <strong>Options → About</strong>;</li><li>добавлен блок с деталями версии и кнопками <strong>Ignore</strong> и <strong>Download</strong>.</li></ul></li></ul><hr><h3 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена ошибка отсутствия подсветки UI-элементов <strong>Props</strong> в режиме <strong>Standalone</strong>.</li></ul><hr><h3 id="network-1" tabindex="-1">Network <a class="header-anchor" href="#network-1" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><p>Добавлена поддержка <strong>form-data</strong> для чтения и подмены трафика.</p></li><li><p>Добавлена возможность сохранять используемые файлы для повторного использования при работе с <strong>Breakpoint</strong> и <strong>form-data</strong>.</p></li><li><p>Добавлены режимы <strong>Rewrite Breakpoint</strong> и <strong>Rewrite Mock</strong>: при наличии существующего перехвата предлагается перезаписать правило вместо создания нового.</p></li><li><p>Добавлена индикация активных <strong>Breakpoint</strong> и <strong>Mock</strong> для запроса; переход по счётчику открывает соответствующий раздел настроек.</p></li><li><p>Добавлен поиск по статус-коду ответа.</p></li><li><p>Расширены возможности <strong>Breakpoint</strong> — добавлен учёт HTTP-метода при перехвате.</p></li><li><p>Исправлена ошибка, при которой инспектор не открывался при срабатывании <strong>Breakpoint</strong>.</p></li><li><p>В контекстное меню запроса добавлены действия:</p><ul><li><strong>Disable / Enable Breakpoint</strong></li><li><strong>Disable / Enable Mock</strong></li><li><strong>Delete Breakpoint / Mock</strong></li><li>пункты отображаются только при наличии соответствующего правила.</li></ul></li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><h4 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h4><ul><li>Базовые настройки приложения (<strong>Display Mode</strong>, <strong>Search Parameters</strong>, <strong>Auto Refresh</strong>, <strong>JSON Editor Mode</strong>) перенесены в отдельный раздел.</li><li>Управление файлом настроек (<strong>Settings Management</strong>) перенесено из шапки вкладки.</li></ul><h4 id="network-2" tabindex="-1">Network <a class="header-anchor" href="#network-2" aria-label="Permalink to &quot;Network&quot;">​</a></h4><ul><li><strong>Search Settings</strong> вынесены в отдельный раздел и стали независимыми.</li><li>Скорректирована вёрстка таблиц <strong>Breakpoints</strong> и <strong>Mocks</strong> — данные больше не растягиваются.</li><li>Добавлена возможность отключения и редактирования ранее созданных правил.</li></ul><h4 id="props-2" tabindex="-1">Props <a class="header-anchor" href="#props-2" aria-label="Permalink to &quot;Props&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li><li><strong>Component Blacklist</strong> перенесён из общего блока настроек.</li><li><strong>Favorite Components</strong> перенесены из общего блока настроек.</li></ul><h4 id="pinia-store" tabindex="-1">Pinia Store <a class="header-anchor" href="#pinia-store" aria-label="Permalink to &quot;Pinia Store&quot;">​</a></h4><ul><li>Управление файлом настроек перенесено в раздел.</li></ul><h4 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h4><ul><li><p>Добавлены кнопки <strong>Release notes</strong> и <strong>Check for updates</strong> (доступно только в <strong>extension</strong>-версии).</p></li><li><p>При наличии новой версии:</p><ul><li><strong>Ignore</strong> отключает повторные уведомления для текущей версии; состояние сбрасывается после выхода более новой версии.</li><li><strong>Download</strong> инициирует загрузку архива с приложением.</li></ul></li></ul><h2 id="_2-3-0-2026-03-16" tabindex="-1">[2.3.0] - 2026-03-16 <a class="header-anchor" href="#_2-3-0-2026-03-16" aria-label="Permalink to &quot;[2.3.0] - 2026-03-16&quot;">​</a></h2><h3 id="network-3" tabindex="-1">Network <a class="header-anchor" href="#network-3" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Добавлена генерация <strong>Postman</strong>-коллекций на основе запросов, собранных во вкладке <strong>Network</strong>.</li><li>В однопанельном режиме кнопка <strong>Copy cURL</strong> заменена контекстным меню с доступом к: <ul><li><strong>Breakpoint</strong></li><li><strong>Mock</strong></li><li><strong>Copy cURL</strong></li></ul></li><li>Добавлена логика вызова контекстного меню (ПКМ) по шапке детализации запроса.</li></ul><hr><h3 id="props-3" tabindex="-1">Props <a class="header-anchor" href="#props-3" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена работа избранного и чёрного списка при работе с <strong>Props</strong>.</li><li>Изменена логика сбора данных с учетом <strong>blacklist</strong>: игнорируемые элементы исключаются на этапе предварительного обхода, а не только скрываются из таблицы, что ускоряет загрузку вкладки.</li><li>Добавлено меню быстрых действий для <strong>Props</strong>.</li><li>Добавлена возможность обновления открытого компонента в режиме чтения.</li><li>Добавлены shortcut-переходы к списку избранного при нажатии на счётчик избранных элементов.</li></ul><hr><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><ul><li>Добавлен функционал избранного для <strong>Pinia Store</strong> включая shortcut-переход.</li><li>Добавлено меню быстрых действий для <strong>Pinia Store</strong>.</li><li>Добавлена возможность обновления открытого элемента в режиме чтения.</li><li>В разделе <strong>Options</strong> доступно создание и редактирование пользовательских избранных элементов, включая поддержку <strong>wildcards</strong>.</li></ul><hr><h3 id="options-1" tabindex="-1">Options <a class="header-anchor" href="#options-1" aria-label="Permalink to &quot;Options&quot;">​</a></h3><ul><li>Изменён алгоритм хранения пользовательских настроек: выбранные файлы теперь сохраняются как локальные копии в хранилище приложения.</li><li><strong>Standalone</strong>-версия переведена на собственное локальное хранилище. Настройки сохраняются между запусками и доступны на разных сайтах без потери данных.</li><li>Режим tree временно отключён — работа с JSON доступна только в text-режиме.</li></ul><h4 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h4><p>В разделе <strong>Options → General → Customize</strong> добавлены настройки визуального оформления приложения:</p><ul><li><strong>Dark / Light</strong> — цветовая схема;</li><li><strong>Image</strong> — фон (<strong>File / Link</strong>) с поддержкой: <ul><li>статичных изображений,</li><li><strong>GIF</strong>,</li><li><strong>MP4</strong>;</li></ul></li><li>Выбор файла через <strong>Browse</strong> или из списка ранее сохранённых;</li><li>Добавление файла по ссылке;</li><li><strong>Image Opacity</strong> — прозрачность;</li><li><strong>Blur</strong> — размытие;</li><li><strong>Noise Intensity / Opacity</strong> — параметры шумового слоя;</li><li><strong>Position (X / Y)</strong> — положение изображения;</li><li><strong>Scale</strong> — масштаб (<strong>100–200%</strong>).</li></ul><hr><h3 id="ui-ux-1" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-1" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Добавлена адаптивная раскладка интерфейса для небольших экранов.</li><li>На широких экранах используется двухпанельный режим: список и детали отображаются одновременно.</li><li>При ширине около <strong>1000px</strong> интерфейс автоматически переключается в однопанельный режим.</li><li>Добавлена поддержка клавиши <strong>Esc</strong> для закрытия активных панелей и диалогов.</li><li>Добавлена поддержка поиска <strong>Ctrl+F</strong> в режиме вкладки <strong>DevTools</strong>.</li><li>Добавлены скелетоны загрузки для таблиц <strong>Props</strong> и <strong>Pinia</strong> вместо текста <strong>Not found</strong>.</li><li>Добавлены настройки отображения колонок для таблиц <strong>Props</strong>, <strong>Pinia</strong> и <strong>Network</strong>.</li><li>Изменён дизайн шеврона для открытия <strong>iframe</strong>.</li><li>Добавлена поддержка контекстного меню (ПКМ) при работе с таблицами.</li></ul><hr><h3 id="производительность-1" tabindex="-1">Производительность <a class="header-anchor" href="#производительность-1" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменена логика обработки <strong>blacklist</strong> во вкладке <strong>Props</strong>: заблокированные элементы больше не участвуют в предварительном обходе, что ускоряет сбор данных и загрузку вкладки.</li></ul><hr><h3 id="исправления" tabindex="-1">Исправления <a class="header-anchor" href="#исправления" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Исправлена область нажатия для блока <strong>JSON</strong> при редактировании во время скролла.</li><li>Исправлены зависания приложения при длительной работе вкладки <strong>Network</strong>.</li><li>Исправлено поведение <strong>Ctrl+A</strong> — выделение применяется только к активному полю ввода.</li><li>Исправлено отображение кнопок сброса и удаления в <strong>disabled</strong>-состоянии.</li><li>Исправлено отображение таблиц в <strong>Options</strong> при большом количестве значений.</li><li>Исправлены стили режима редактирования <strong>JSON</strong>.</li><li>Внесены косметические правки оформления.</li></ul><h2 id="_2-4-0-2026-04-05" tabindex="-1">[2.4.0] - 2026-04-05 <a class="header-anchor" href="#_2-4-0-2026-04-05" aria-label="Permalink to &quot;[2.4.0] - 2026-04-05&quot;">​</a></h2><h3 id="network-4" tabindex="-1">Network <a class="header-anchor" href="#network-4" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>При установке паузы, перехватчики инспектора теперь снимаются, в стандартных Devtools будет отображаться оригинальный инициатор вместо injected.ts.</li><li>Таблица <strong>Network</strong> переведена на виртуализацию для ускорения работы и снижения фризов.</li><li>Изменено стартовое окно при открытии детализации запроса — по умолчанию теперь открывается <strong>Response</strong>.</li><li>При срабатывании <strong>Breakpoint</strong> остановленный метод автоматически открывается на вкладке <strong>Request</strong>.</li><li>В списках <strong>Search by</strong> на вкладке <strong>Network</strong> и в разделе <strong>Options</strong> добавлена поддержка поиска по колонке <strong>Name</strong>.</li></ul><hr><h3 id="props-4" tabindex="-1">Props <a class="header-anchor" href="#props-4" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p>Значительно ускорена работа с <strong>Props</strong>, что позволяет безопасно использовать автообновление данных.</p></li><li><p>В таблице <strong>Props</strong> колонка <strong>Props</strong> заменена на <strong>Passed</strong> и <strong>Declared</strong> (все колонки доступны для скрытия):</p><ul><li><strong>Passed</strong> — количество <strong>Props</strong>, полученных в текущий момент.</li><li><strong>Declared</strong> — количество возможных <strong>Props</strong>, объявленных для элемента.</li></ul></li><li><p>В правом блоке детализации <strong>Props</strong> данные разделены на две вкладки:</p><ul><li><strong>Passed</strong> — фактически переданные <strong>Props</strong> (открывается по умолчанию).</li><li><strong>Declared</strong> — все <strong>Props</strong>, объявленные компонентом.</li></ul></li><li><p>В блоке <strong>Details Props</strong> добавлен параметр <strong>Size</strong>.</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (<strong>Props Inspector</strong>) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (**Props Inspector**)&quot;">​</a></h4><ul><li>Добавлен режим выбора элементов на странице по аналогии с <strong>Chrome DevTools Elements</strong>.</li><li>Позволяет выбрать элемент прямо на странице и быстро отфильтровать список <strong>Props</strong>.</li><li>Подсвечивает <strong>Vue</strong>-компоненты при наведении.</li><li>Показывает краткую информацию об элементе: <strong>Name</strong>, <strong>Root element</strong>, <strong>Received Props</strong>, <strong>Nested components</strong>.</li><li>После выбора отображает <strong>Props</strong> только выбранного элемента и его вложенных компонентов.</li><li>Фильтр можно быстро сбросить через бейдж <strong>Filtered</strong>.</li></ul><hr><h3 id="ui-ux-2" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-2" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="оконныи-режим" tabindex="-1">Оконный режим <a class="header-anchor" href="#оконныи-режим" aria-label="Permalink to &quot;Оконный режим&quot;">​</a></h4><ul><li>Добавлена поддержка оконного режима приложения с сохранением выбранного положения для обеих версий запуска.</li><li>Обновлён шеврон открытия <strong>iframe</strong> — добавлена иконка перетаскивания.</li><li>Добавлена возможность закрепления шеврона по любой из четырёх сторон браузера с автоматическим растягиванием окна приложения по высоте.</li></ul><h4 id="настроики-автозапуска" tabindex="-1">Настройки автозапуска <a class="header-anchor" href="#настроики-автозапуска" aria-label="Permalink to &quot;Настройки автозапуска&quot;">​</a></h4><ul><li><p>Добавлена возможность задать список сайтов для автоматического запуска приложения (<strong>Whitelist</strong>) и список исключений, где запуск приложения и отображение шеврона запрещены (<strong>Blacklist</strong>).</p></li><li><p>Добавлено <strong>popup</strong>-меню расширения с быстрыми действиями:</p><ul><li><strong>Forced Launch</strong> - Принудительный запуск приложения (игнорирует ограничения white и blacklist site, а так же внутреннее ограничение на статичные сайты);</li><li><strong>Reset Settings</strong> - Сброс всех настроек расширения.</li></ul></li></ul><h4 id="прочие-улучшения-интерфеиса" tabindex="-1">Прочие улучшения интерфейса <a class="header-anchor" href="#прочие-улучшения-интерфеиса" aria-label="Permalink to &quot;Прочие улучшения интерфейса&quot;">​</a></h4><ul><li>Исправлены стили <strong>JSON</strong> для больших объёмов данных.</li><li>Добавлена возможность точного поиска при вводе значения в кавычках: без кавычек поиск работает в режиме <strong>like</strong>.</li><li>Внесены мелкие визуальные правки интерфейса.</li><li>Доработана логика закрытия вкладок по клавише <strong>Esc</strong> в режиме <strong>DevTools</strong>: сначала выполняется выход из вкладок, а если закрывать больше нечего — открывается консоль <strong>DevTools</strong>.</li></ul><hr><h3 id="производительность-2" tabindex="-1">Производительность <a class="header-anchor" href="#производительность-2" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменён механизм определения <strong>Props</strong> и <strong>Store</strong> — получение данных значительно ускорено.</li><li>Увеличены лимиты на максимальное количество вычитываемых <strong>Props</strong>.</li><li>Проведён рефакторинг внутренней структуры проекта: удалены неиспользуемые модули, мёртвый код и дублирующая логика.</li></ul><hr><h3 id="документация" tabindex="-1">Документация <a class="header-anchor" href="#документация" aria-label="Permalink to &quot;Документация&quot;">​</a></h3><ul><li>У проекта появилась полноценная документация.</li><li>На лендинговой странице добавлен раздел <strong>Documentation</strong>.</li><li>В разделе <strong>Options → About</strong> добавлен быстрый переход к документации.</li></ul><hr><h3 id="исправления-1" tabindex="-1">Исправления <a class="header-anchor" href="#исправления-1" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Заблокирована работа стандартного ПКМ внутри контекстного меню приложения.</li><li>Исправлено ложное определение избранного в детализации <strong>Props</strong> при совпадении имён.</li><li>Доработана логика поиска в режиме <strong>DevTools</strong>: исправлен кейс, при котором поиск мог перестать работать; добавлен сброс подсветки при очистке поля и закрытии поиска.</li><li>Исправлена ошибка при сохранении изменений <strong>Getters</strong> в <strong>Pinia Store</strong>.</li><li>Исправлена ошибка получения данных <strong>Props</strong> во <strong>Vue</strong> при локальной разработке.</li><li>Исправлены ошибки работы <strong>Network</strong> при локальной разработке.</li></ul><h2 id="_2-5-0-2026-05-17" tabindex="-1">[2.5.0] - 2026-05-17 <a class="header-anchor" href="#_2-5-0-2026-05-17" aria-label="Permalink to &quot;[2.5.0] - 2026-05-17&quot;">​</a></h2><h3 id="network-5" tabindex="-1">Network <a class="header-anchor" href="#network-5" aria-label="Permalink to &quot;Network&quot;">​</a></h3><p>Добавлена возможность свернуть / развернуть разделы заголовком network Приложение теперь запоминает последнюю вкладку где работал пользователь, при открытии запроса, последующий будет открываться на той же вкладке. где пользователь работал с предыдущим запросом</p><p><strong>Глобальная приостановка Breakpoint и Mock</strong><br> На панели <strong>Network</strong> (справа, рядом с управлением записью журнала) добавлены две кнопки: <strong>приостановка / возобновление всех правил breakpoint</strong> (иконка с кругом и паузой, активное состояние — янтарный акцент) и <strong>приостановка / возобновление всех mock response</strong> (иконка shuffle, активное состояние — фиолетовый акцент). Правила не удаляются из <strong>Options → Network</strong>; при «выключении» перехват соответствующего типа на странице не выполняется. Те же флаги задаются чекбоксами <strong>Enable breakpoint rules</strong> и <strong>Enable mock responses</strong> в настройках списков; панель и Options синхронизированы. Индикаторы <strong>bp</strong> и <strong>mock</strong> в приглушённом стиле показывают, что глобально применение правил отключено.</p><p><strong>Режим захвата сети: Advanced (расширенный)</strong><br> В настройках Network доступен режим <strong>Advanced mode</strong>: расширение запрашивает дополнительные права и собирает <strong>полный набор заголовков</strong> запроса и ответа (в том числе те, что в обычной вкладке Network в DevTools не всегда видны ограничениями страницы). Режим <strong>Classic mode</strong> (ранее условно «сохранённый» снимок) по-прежнему показывает только заголовки в рамках стандартного, «классического» просмотра без обхода этих ограничений.</p><p><strong>Важно для Standalone</strong><br> Расширенный захват и связанные с ним возможности <strong>недоступны в Standalone</strong>: там по-прежнему используется только классический сценарий без расширенных заголовков и без меню/настроек Advanced.</p><p><strong>Что даёт Advanced mode в Network</strong></p><ul><li><strong>Дополнительные заголовки</strong> в блоках Request / Response на вкладке заголовков выбранного запроса.</li><li><strong>Закрепление заголовков (pin)</strong> — выбранные имена можно закрепить вверху списка отдельно для <strong>запроса</strong> и <strong>ответа</strong>; список закреплений можно править в настройках (только при включённом Advanced).</li><li><strong>Свои ссылки по заголовку (header links)</strong> — для хоста и шаблона URL можно открывать внешний ресурс с подстановкой значения заголовка (например, переход к <strong>трейсам</strong>, поиску по ID, внутренним дашбордам). Управление правилами — в настройках Network и через контекстное меню строки заголовка (при Advanced).</li><li>Настройки <strong>Header links</strong> и <strong>Pinned headers</strong> в опциях отображаются <strong>только при включённом Advanced mode</strong>, чтобы не перегружать интерфейс в классическом режиме.</li></ul><hr><h3 id="ui-ux-3" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-3" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><p><strong>JSON Mode (Options → General)</strong><br> В разделе <strong>Options → General</strong> добавлен переключатель <strong>JSON Mode</strong> с двумя вариантами:</p><ul><li><strong>Classic</strong> — встроенный текстовый редактор с подсветкой синтаксиса (<strong>Prism</strong>, <strong>JsonTextEditor</strong>): один текстовый вид без дерева, оптимизирован для больших фрагментов (ослабление подсветки на очень длинных JSON и облегчённый просмотр для крупных не-JSON тел только для чтения).</li><li><strong>Advanced</strong> — редактор на базе <strong>vanilla-jsoneditor</strong>: два представления одного JSON — <strong>Text</strong> (код) и <strong>Tree</strong> (структура); переключение с панели инструментов, последний выбранный режим (<strong>Text</strong> / <strong>Tree</strong>) <strong>сохраняется</strong> в настройках (<strong>json.mode</strong>). В Advanced доступны <strong>Format</strong> / <strong>Compact</strong> (где разрешено редактирование), <strong>Undo / Redo</strong>, <strong>поиск</strong>, копирование; в дереве — свёртка/развёртка узлов, навигация по пути, контекстные меню и связанные с деревом сценарии сортировки и правки.</li></ul><p>Переключатель <strong>Classic / Advanced</strong> задаёт реализацию для <strong>JSON</strong> в интерфейсе (тела запросов/ответов в <strong>Network</strong>, <strong>Mock</strong>, снимки <strong>Pinia</strong>, JSON на <strong>Props</strong> и т.д.). Для контента не в формате JSON по-прежнему используется текстовый просмотр с подсветкой, где это поддерживается.</p>',102)])])}const c=r(l,[["render",i]]);export{d as __pageData,c as default};
